"use client";

import { useRouter } from "next/navigation";
import { Link } from "@/lib/navigation";
import { useTranslations } from "next-intl";
import type { PostWithAuthor } from "@/lib/data/posts";

function authorDisplay(profiles: PostWithAuthor["profiles"]): string {
  if (!profiles) return "—";
  const p = Array.isArray(profiles) ? profiles[0] : profiles;
  return p?.display_name ?? "—";
}

export function DashboardBlogs({
  posts,
  isAdmin,
  currentUserId,
  deletePostAction,
}: {
  posts: PostWithAuthor[];
  isAdmin: boolean;
  currentUserId: string;
  deletePostAction: (postId: string) => Promise<{ error?: string; success?: boolean }>;
}) {
  const t = useTranslations();
  const router = useRouter();

  async function handleDelete(postId: string) {
    if (!confirm(t("dashboard.confirmDelete"))) return;
    const result = await deletePostAction(postId);
    if (result.error) {
      alert(result.error);
      return;
    }
    router.refresh();
  }

  return (
    <div className="space-y-4">
      {posts.length === 0 ? (
        <p className="text-gray-500 dark:text-gray-400">{t("dashboard.noPosts")}</p>
      ) : (
        <ul className="divide-y divide-gray-200 dark:divide-gray-700">
          {posts.map((post) => {
            const canEdit = isAdmin || post.author_id === currentUserId;
            return (
              <li key={post.id} className="py-4 first:pt-0">
                <div className="rounded-lg border border-gray-200 dark:border-gray-700 p-4 bg-white dark:bg-gray-900">
                  {isAdmin && (
                    <p className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-2">
                      {t("dashboard.authorLabel")}: {authorDisplay(post.profiles)}
                    </p>
                  )}
                  <div className="flex flex-wrap items-center justify-between gap-2">
                    <div>
                      <span className="font-mono text-sm text-gray-900 dark:text-white">{post.slug}</span>
                      <span className="ml-2 text-xs text-gray-500 dark:text-gray-400">
                        {post.status} · {post.primary_locale}
                      </span>
                      <span className="ml-2 text-xs text-gray-400">
                        {new Date(post.updated_at).toLocaleDateString()}
                      </span>
                    </div>
                    <div className="flex gap-2">
                      {canEdit && (
                        <>
                          <Link
                            href={`/dashboard/posts/${post.id}/edit`}
                            className="text-sm text-blue-600 dark:text-blue-400 hover:underline"
                          >
                            {t("common.edit")}
                          </Link>
                          <button
                            type="button"
                            onClick={() => handleDelete(post.id)}
                            className="text-sm text-red-600 dark:text-red-400 hover:underline"
                          >
                            {t("common.delete")}
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              </li>
            );
          })}
        </ul>
      )}
    </div>
  );
}
